public class Power {
    public static int pow(int base, int exp) {
        if (exp == 0) return 1;
        if (exp % 2 == 0) {
            int half = pow(base, exp / 2);
            return half * half;
        }
        return base * pow(base, exp - 1);
    }

    public static void main(String[] args) {
        System.out.println(pow(2, 4));
        System.out.println(pow(3, 3));
    }
}
